  1→import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query"
  2→import { get, post, put, del } from "@/lib/api"
  3→import type { Exam, PageResult } from "@/types"
  4→
  5→const ADMIN_EXAMS_KEY = "admin-exams"
  6→
  7→/** 管理员获取试卷列表（分页） */
  8→export function useAdminExamList(page: number, size: number) {
  9→  return useQuery<PageResult<Exam>>({
 10→    queryKey: [ADMIN_EXAMS_KEY, page, size],
 11→    queryFn: () => get<PageResult<Exam>>(`/api/admin/exams?page=${page}&size=${size}`),
 12→  })
 13→}
 14→
 15→/** 管理员获取试卷详情 */
 16→export function useAdminExamDetail(id: number) {
 17→  return useQuery<Exam>({
 18→    queryKey: [ADMIN_EXAMS_KEY, "detail", id],
 19→    queryFn: () => get<Exam>(`/api/admin/exams/${id}`),
 20→    enabled: id > 0,
 21→  })
 22→}
 23→
 24→/** 创建试卷 */
 25→export function useCreateExam() {
 26→  const queryClient = useQueryClient()
 27→  return useMutation({
 28→    mutationFn: (data: Partial<Exam>) => post<Exam>("/api/admin/exams", data),
 29→    onSuccess: () => {
 30→      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
 31→    },
 32→  })
 33→}
 34→
 35→/** 更新试卷 */
 36→export function useUpdateExam() {
 37→  const queryClient = useQueryClient()
 38→  return useMutation({
 39→    mutationFn: ({ id, ...data }: Partial<Exam> & { id: number }) =>
 40→      put<void>(`/api/admin/exams/${id}`, data),
 41→    onSuccess: () => {
 42→      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
 43→    },
 44→  })
 45→}
